import React, { useState, useEffect } from "react";
import axios from "axios";

const Home = ({ userEmail, handleLogout }) => {
    const [tours, setTours] = useState([]);
    const [bookings, setBookings] = useState([]);
    const [clientId, setClientId] = useState(null);

    useEffect(() => {
        const fetchClientData = async () => {
            try {
                const response = await axios.get("http://192.168.66.59:5000/api/clients");
                const client = response.data.find((c) => c.email === userEmail);
                if (client) {
                    setClientId(client.id);
                    fetchBookings(client.id);
                }
            } catch (error) {
                console.error("Error fetching client data:", error);
            }
        };

        const fetchTours = async () => {
            try {
                const response = await axios.get("http://192.168.66.59:5000/api/tours");
                setTours(response.data);
            } catch (error) {
                console.error("Error fetching tours:", error);
            }
        };

        const fetchBookings = async (clientId) => {
            try {
                const response = await axios.get("http://192.168.66.59:5000/api/bookings");
                setBookings(response.data.filter((booking) => booking.client_id === clientId));
            } catch (error) {
                console.error("Error fetching bookings:", error);
            }
        };

        if (userEmail) {
            fetchClientData();
            fetchTours();
        }
    }, [userEmail]);

    const bookTour = async (tourId) => {
        if (!clientId) return;
        try {
            await axios.post("http://192.168.66.59:5000/api/bookings", {
                client_id: clientId,
                tour_id: tourId,
                booking_date: new Date().toISOString(),
                status: "confirmed"
            });
            fetchBookings(clientId);
        } catch (error) {
            console.error("Error booking tour:", error);
        }
    };

    return (
        <div>
            <h2>Available Tours</h2>
            <ul>
                {tours.map((tour) => (
                    <li key={tour.id}>
                        {tour.name} - {tour.description}
                        <button onClick={() => bookTour(tour.id)}>Book</button>
                    </li>
                ))}
            </ul>

            <h2>Your Bookings</h2>
            <ul>
                {bookings.length > 0 ? (
                    bookings.map((booking) => (
                        <li key={booking.id}>Tour ID: {booking.tour_id}, Status: {booking.status}</li>
                    ))
                ) : (
                    <p>No bookings yet.</p>
                )}
            </ul>

            <button onClick={handleLogout}>Logout</button>
        </div>
    );
};

export default Home;
